import test, { expect } from "@playwright/test";
import { numDifferentIntegers } from "../../../../src/leetcode/2026/march/task-1_15-March/task-1_15-March";

test.describe("Number of Different Integers in a String", async () => {
  test("Number of Different Integers in a String case 1", async () => {
    expect(numDifferentIntegers("a123bc34d8ef34")).toBe(3);
  });

  test("Number of Different Integers in a String case 2", async () => {
    expect(numDifferentIntegers("a1b01c001")).toBe(1);
  });

  test("Number of Different Integers in a String case 3", async () => {
    let str =
      "";
    expect(numDifferentIntegers(str)).toBe(3);

    // 
    // 
    // c79487281900662343830648295410
  });
});
